SELECT ${1:columns}
FROM ${2:table}
WHERE ${3:condition}
ORDER BY ${4:column}
LIMIT ${5:100};

CREATE TABLE ${1:schema}.${2:table_name} (
	${3:id} INTEGER IDENTITY(1,1),
	${4:column_name} ${5:VARCHAR(256)},
	PRIMARY KEY (${3:id})
)
DISTSTYLE ${6:KEY}
DISTKEY (${7:id})
SORTKEY (${8:id});

COPY ${1:table_name}
FROM '${2:s3://bucket/path/}'
IAM_ROLE '${3:arn:aws:iam::role/RedshiftRole}'
FORMAT AS ${4:CSV}
IGNOREHEADER ${5:1}
REGION '${6:us-east-1}';

UNLOAD ('${1:SELECT * FROM table}')
TO '${2:s3://bucket/path/}'
IAM_ROLE '${3:arn:aws:iam::role/RedshiftRole}'
FORMAT AS ${4:PARQUET}
ALLOWOVERWRITE;
